const v4seg = '([0-9]|[1-9][0-9]|1[0-9]{2}|2[0-4][0-9]|25[0-5])'
const ipv4 = `((?:(?:${v4seg})\\.){3}(?:${v4seg}))`
const hexa = '([0-9A-Fa-f]{1,4})'
const ipv6 = `((((${hexa}:){7}(${hexa}|:))|((${hexa}:){6}(:${hexa}|(${ipv4})|:))|((${hexa}:){5}(((:${hexa}){1,2})|:(${ipv4})|:))|((${hexa}:){4}(((:${hexa}){1,3})|((:${hexa})?:(${ipv4}))|:))|((${hexa}:){3}(((:${hexa}){1,4})|((:${hexa}){0,2}:(${ipv4}))|:))|((${hexa}:){2}(((:${hexa}){1,5})|((:${hexa}){0,3}:(${ipv4}))|:))|((${hexa}:){1}(((:${hexa}){1,6})|((:${hexa}){0,4}:(${ipv4}))|:))|(:(((:${hexa}){1,7})|((:${hexa}){0,5}:(${ipv4}))|:)))(%.+)?)`;

// const regexipv4 = /^(?:(25[0-5]|2[0-4][0-9]|1[0-9]{2}|[1-9][0-9]|[0-9])\.){3}(?:25[0-5]|2[0-4][0-9]|1[0-9]{2}|[1-9][0-9]|[0-9])$/
// const regexipv4 = /^(?:(25[0-5]|2[0-4][0-9]|1[0-9]{2}|[1-9][0-9]|[0-9])\.){3}(?:25[0-5]|2[0-4][0-9]|1[0-9]{2}|[1-9][0-9]|[0-9])$/

const regexipv4 = /^(?:[0-9]|[1-9][0-9]|1[0-9]{2}|2[0-4][0-9]|25[0-5])(?:\.(?:[0-9]|[1-9][0-9]|1[0-9]{2}|2[0-4][0-9]|25[0-5])){3}$/

/*
ipv6 =
aabb: aabb: aabb: aabb: aabb: aabb: aabb: ffff
8 octets
les 0 de debut de chaine peuvent etre supprime
0aaa: => aaa:
00aa: => aa:
000a: => a
0000: => 0
------------

7 + 1
0-7 + ::
0-6 + :: + 0-1
0-5 + :: + 0-2
0-4 + :: + 0-3
0-3 + :: + 0-4
0-2 + :: + 0-3
0-1 + :: + 0-2
:: + 0-7
*/

const regexipv6 = new RegExp(`^${ipv6}$`, 'i')

//const copyv6 = /^(?:(?:[a-fA-F0-9]{1,4}:){7}(?:[a-fA-F0-9]{1,4}|:)|(?:[a-fA-F0-9]{1,4}:){6}(?:(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)(?:\.(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)){3}|:[a-fA-F0-9]{1,4}|:)|(?:[a-fA-F0-9]{1,4}:){5}(?::(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)(?:\.(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)){3}|(?::[a-fA-F0-9]{1,4}){1,2}|:)|(?:[a-fA-F0-9]{1,4}:){4}(?:(?::[a-fA-F0-9]{1,4}){0,1}:(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)(?:\.(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)){3}|(?::[a-fA-F0-9]{1,4}){1,3}|:)|(?:[a-fA-F0-9]{1,4}:){3}(?:(?::[a-fA-F0-9]{1,4}){0,2}:(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)(?:\.(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)){3}|(?::[a-fA-F0-9]{1,4}){1,4}|:)|(?:[a-fA-F0-9]{1,4}:){2}(?:(?::[a-fA-F0-9]{1,4}){0,3}:(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)(?:\.(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)){3}|(?::[a-fA-F0-9]{1,4}){1,5}|:)|(?:[a-fA-F0-9]{1,4}:){1}(?:(?::[a-fA-F0-9]{1,4}){0,4}:(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)(?:\.(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)){3}|(?::[a-fA-F0-9]{1,4}){1,6}|:)|(?::(?:(?::[a-fA-F0-9]{1,4}){0,5}:(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)(?:\.(?:25[0-5]|2[0-4]0-9|10-90-9|[1-9]0-9|0-9)){3}|(?::[a-fA-F0-9]{1,4}){1,7}|:)))(?:%[0-9a-zA-Z]{1,})?$/i
//const copyv6 = /^(?:(?:::(?:[0-9a-f]{1,4}:){0,5}|[0-9a-f]{1,4}::(?:[0-9a-f]{1,4}:){0,4}|(?:[0-9a-f]{1,4}:){2}:(?:[0-9a-f]{1,4}:){0,3}|(?:[0-9a-f]{1,4}:){3}:(?:[0-9a-f]{1,4}:){0,2}|(?:[0-9a-f]{1,4}:){4}:(?:[0-9a-f]{1,4}:)?|(?:[0-9a-f]{1,4}:){5}:|(?:[0-9a-f]{1,4}:){6})(?:(?:25[0-5]|2[0-4][0-9]|[01]?[0-9]{1,2})\.){3}(?:25[0-5]|2[0-4][0-9]|[01]?[0-9]{1,2})|:(?::|(?::[0-9a-f]{1,4}){1,7})|[0-9a-f]{1,4}:(?::|(?::[0-9a-f]{1,4}){1,6})|(?:[0-9a-f]{1,4}:){2}(?::|(?::[0-9a-f]{1,4}){1,5})|(?:[0-9a-f]{1,4}:){3}(?::|(?::[0-9a-f]{1,4}){1,4})|(?:[0-9a-f]{1,4}:){4}(?::|(?::[0-9a-f]{1,4}){1,3})|(?:[0-9a-f]{1,4}:){5}(?::|(?::[0-9a-f]{1,4}){1,2})|(?:[0-9a-f]{1,4}:){6}(?::|(?::[0-9a-f]{1,4}))|(?:[0-9a-f]{1,4}:){7}:|(?:[0-9a-f]{1,4}:){7}[0-9a-f]{1,4})(?:%[0-9a-z]+)?$/i

/**
 * test if v is ipv4
 * @param {string} v 
 */
const isIpv4 = (v) => regexipv4.test(v)
/**
 * test if v is ipv6
 * @param {string} v 
 */
const isIpv6 = (v) => regexipv6.test(v)
/**
 * test if v is ip (v4 or v6)
 * @param {string} v 
 */
const isIp = (v) => regexipv4.test(v) || regexipv6.test(v)

const checkHeaders = [
  'x-client-ip',
  'cf-connecting-ip',
  'fastly-client-ip',
  'true-client-ip',
  'x-real-ip',
  'x-cluster-client-ip',
  'x-forwarded',
  'forwarded-for',
  'forwarded'
]

/**
 * get client ip from XForwardedFor header
 * @param {string|null} v 
 * @returns {string|null}
 */
function getIpXForwardedFor(v = null) {
  if (v === null) {
    return null
  }
  if (toString.call(v) !== '[object String]') {
    throw new TypeError(`Expected a string, got "${typeof v}"`)
  }
  return v.split(',').shift().trim()
}

/**
 * custum call for get ip from request
 * @param {http.IncomingMessage} req 
 * @param {getIpFromRequestBuilderOption} options 
 * @returns {string|null}
 */
function getIpFromRequestPrivate(req, options = {}) {
  if (req?.headers) {
    if (req.headers?.['x-forwarded-for']) {
      const xForwardedFor = getIpXForwardedFor(req.headers['x-forwarded-for'])
      if (xForwardedFor !== null && isIp(xForwardedFor)) {
        return xForwardedFor
      }
    }
    const listOfHeaders = options?.headers ? [...checkHeaders, options?.headers] : checkHeaders
    for (const index of listOfHeaders) {
      if (req.headers?.[index] && isIp(req.headers[index])) {
        return req.headers[index]
      }
    }
  }
  if (req?.connection) {
    if (req?.connection?.remoteAddress && isIp(req.connection.remoteAddress)) {
      return req.connection.remoteAddress
    }
    if (req?.connection?.socket?.remoteAddress && isIp(req.connection.socket.remoteAddress)) {
      return req.connection.socket.remoteAddress
    }
  }
  if (req?.socket?.remoteAddress && isIp(req.socket.remoteAddress)) {
    return req.socket.remoteAddress
  }
  if (req?.info?.remoteAddress && isIp(req.info.remoteAddress)) {
    return req.info.remoteAddress
  }
  if (req?.requestContext?.identity?.sourceIp && isIp(req.requestContext.identity.sourceIp)) {
    return req.requestContext.identity.sourceIp
  }
  return null;
}

/**
 * get ip from request
 * @param {http.IncomingMessage} req 
 * @returns {string|null}
 */
const getIpFromRequest = req => getIpFromRequestPrivate(req)

/**
 * generate custom getIpFromRequest function
 * @param {*} options 
 * @return {(req: http.IncomingMessage) => string|null}
 */
function getIpFromRequestBuilder(options = {}) {
  return req => getIpFromRequestPrivate(req, options)
}

module.exports = {
  ipv4,
  ipv6,
  isIpv4,
  isIpv6,
  isIp,
  getIpFromRequest,
  getIpFromRequestBuilder
}
